/* BTAccordion styles — Figma 2473:2493
 *
 * BTAccordion is the group wrapper; BTAccordionItem is the individual panel.
 * Default visual only: separator-based, no card chrome.
 * For card-style panels, see BTAccordionCard.css.
 *
 * Architecture:
 *   .bt-accordion-group          — group wrapper (BTAccordion root)
 *   .bt-accordion                — single item root (BTAccordionItem)
 *   .bt-accordion--open          — currently expanded state
 *   .bt-accordion--disabled      — non-interactive
 *   .bt-accordion__header        — clickable trigger row
 *   .bt-accordion__header--static — non-interactive header (no child slot)
 *   .bt-accordion__title-wrap    — flex-col wrapper for title + subtext
 *   .bt-accordion__title         — primary label
 *   .bt-accordion__subtext       — secondary label
 *   .bt-accordion__chevron       — rotating arrow icon
 *   .bt-accordion__body          — CSS-grid height animating wrapper
 *   .bt-accordion__body-inner    — overflow:hidden inner
 *   .bt-accordion__body-content  — padding wrapper
 *   .bt-accordion__separator     — 1px divider
 */

/* ── Group wrapper ───────────────────────────────────────────────────────── */

.bt-accordion-group {
  display: flex;
  flex-direction: column;
  width: 100%;
}

/* ── Single item root ────────────────────────────────────────────────────── */

.bt-accordion {
  display: flex;
  flex-direction: column;
  width: 100%;
  box-sizing: border-box;
}

/* Disabled */
.bt-accordion--disabled {
  opacity: 0.5;
  pointer-events: none;
}

/* ── Header button ───────────────────────────────────────────────────────── */

.bt-accordion__header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: var(--space-sm);
  width: 100%;
  padding: 8px 0; /* default variant: 8px vertical, no horizontal */
  background: none;
  border: none;
  cursor: pointer;
  user-select: none;
  text-align: start;
  transition: background 0.15s ease;
}

.bt-accordion__header:focus-visible {
  outline: 2px solid var(--color-brand-primary);
  outline-offset: 2px;
  border-radius: var(--radius-sm);
}

/* ── Static header — no chevron, no cursor: pointer ─────────────────────── */

.bt-accordion__header--static {
  display: flex;
  align-items: flex-start;
  gap: var(--space-sm);
  width: 100%;
  padding: 8px 0;
  text-align: start;
}

/* ── Title + subtext column ──────────────────────────────────────────────── */

.bt-accordion__title-wrap {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
  flex: 1;
  min-width: 0;
}

/* ── Title ───────────────────────────────────────────────────────────────── */

.bt-accordion__title {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm); /* 14px */
  font-weight: var(--typography-font-weight-medium); /* 500 */
  line-height: var(--typography-line-height-xs);
  color: var(--text-primary);
  margin: 0;
}

/* ── Subtext ─────────────────────────────────────────────────────────────── */

.bt-accordion__subtext {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-xs); /* 12px */
  font-weight: var(--typography-font-weight-medium); /* 500 */
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  margin: 0;
}

/* ── Chevron ─────────────────────────────────────────────────────────────── */

.bt-accordion__chevron {
  flex-shrink: 0;
  width: 16px;
  height: 16px;
  margin-top: var(--space-2xs);
  color: var(--text-secondary);
  display: flex;
  align-items: center;
  justify-content: center;
  transition: transform 0.25s cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-accordion--open .bt-accordion__chevron {
  transform: rotate(180deg);
}

/* ── Animated body — CSS grid height trick ───────────────────────────────── */

.bt-accordion__body {
  display: grid;
  grid-template-rows: 0fr;
  transition: grid-template-rows 0.28s cubic-bezier(0.4, 0, 0.2, 1);
  overflow: hidden;
}

.bt-accordion--open .bt-accordion__body {
  grid-template-rows: 1fr;
}

.bt-accordion__body-inner {
  min-height: 0;
}

/* Small bottom padding before the separator */
.bt-accordion__body-content {
  padding-bottom: var(--space-sm);
}

/* ── Separator ───────────────────────────────────────────────────────────── */

.bt-accordion__separator {
  height: 1px;
  background: var(--border-primary);
  width: 100%;
  flex-shrink: 0;
}

/* ── Disabled text colors ────────────────────────────────────────────────── */

.bt-accordion--disabled .bt-accordion__title {
  color: var(--text-disabled);
}

.bt-accordion--disabled .bt-accordion__subtext {
  color: var(--text-disabled);
}

/**
 * BTAccordion — group wrapper for collapsible accordion panels (Figma 2473:2493).
 *
 * Manages single-open-at-a-time (type="single") or any-number-open
 * (type="multiple") state across BTAccordionItem children.
 * Supports controlled (value + onValueChange) and uncontrolled modes.
 * No visual chrome of its own.
 *
 * For a card-style expandable panel with its own header, use BTAccordionCard.
 *
 * @example
 * ```ts
 * // Single (default) — uncontrolled
 * // <BTAccordion>
 * //   <BTAccordionItem value="a" title="First">Content A</BTAccordionItem>
 * //   <BTAccordionItem value="b" title="Second">Content B</BTAccordionItem>
 * // </BTAccordion>
 *
 * // Multiple — controlled
 * // const [open, setOpen] = useState<string[]>([]);
 * // <BTAccordion type="multiple" value={open} onValueChange={setOpen}>
 * //   <BTAccordionItem value="a" title="First">Content A</BTAccordionItem>
 * //   <BTAccordionItem value="b" title="Second">Content B</BTAccordionItem>
 * // </BTAccordion>
 * ```
 */
import './BTAccordion.css';
import { createContext, useContext, useState } from 'react';
import type { BTAccordionContext, BTAccordionProps } from './BTAccordion.types';

export const AccordionContext = createContext<BTAccordionContext | null>(null);

/** Internal hook — consumed by BTAccordionItem. */
export function useAccordionContext() {
  return useContext(AccordionContext);
}

export function BTAccordion({
  type = 'single',
  value,
  onValueChange,
  className,
  children,
}: BTAccordionProps) {
  const isControlled = value !== undefined;

  const [internalSingle, setInternalSingle] = useState<string | null>(null);
  const [internalMultiple, setInternalMultiple] = useState<string[]>([]);

  function isItemOpen(itemValue: string): boolean {
    if (type === 'multiple') {
      const arr = isControlled
        ? (Array.isArray(value) ? value : [])
        : internalMultiple;
      return arr.includes(itemValue);
    }
    const single = isControlled
      ? (typeof value === 'string' ? value : null)
      : internalSingle;
    return single === itemValue;
  }

  function toggle(itemValue: string) {
    if (type === 'multiple') {
      const current = isControlled
        ? (Array.isArray(value) ? value : [])
        : internalMultiple;
      const next = current.includes(itemValue)
        ? current.filter((v) => v !== itemValue)
        : [...current, itemValue];
      if (!isControlled) setInternalMultiple(next);
      (onValueChange as ((v: string[]) => void) | undefined)?.(next);
    } else {
      const current = isControlled
        ? (typeof value === 'string' ? value : null)
        : internalSingle;
      const next = current === itemValue ? null : itemValue;
      if (!isControlled) setInternalSingle(next);
      (onValueChange as ((v: string | null) => void) | undefined)?.(next);
    }
  }

  const context: BTAccordionContext = { isItemOpen, toggle };

  const rootClass = ['bt-accordion-group', className].filter(Boolean).join(' ');

  return (
    <AccordionContext.Provider value={context}>
      <div className={rootClass}>{children}</div>
    </AccordionContext.Provider>
  );
}

BTAccordion.displayName = 'BTAccordion';

/**
 * BTAccordion — Figma node 2473:2493
 * https://www.figma.com/design/WANr9drWYNYbMPuT2sMeHi/?node-id=2473-2493
 */
import type React from 'react';

export type BTAccordionType = 'single' | 'multiple';

/** Internal context shared from BTAccordion group to BTAccordionItem children. */
export interface BTAccordionContext {
  isItemOpen: (value: string) => boolean;
  toggle: (value: string) => void;
}

/** Props for the BTAccordion group wrapper. */
export interface BTAccordionProps {
  /**
   * Controls whether one or many items can be open simultaneously.
   * @default 'single'
   */
  type?: BTAccordionType;
  /**
   * The value (key) of the currently open item (single) or open items (multiple).
   * `null` means all items are collapsed (single mode).
   * `[]` means all items are collapsed (multiple mode).
   * Omit for uncontrolled mode; pair with onValueChange for controlled.
   */
  value?: string | null | string[];
  /** Called when the user expands/collapses an item. */
  onValueChange?: ((value: string | null) => void) | ((value: string[]) => void);
  /** Extra CSS class applied to the root element. */
  className?: string;
  children?: React.ReactNode;
}

/** Props for a single BTAccordionItem. */
export interface BTAccordionItemProps {
  /** Unique key identifying this item within the group. */
  value: string;
  /** Header title text. */
  title: string;
  /** Optional supporting content below the title. Accepts strings, JSX, or null. */
  subtext?: React.ReactNode;
  /** Disable interaction for this item. */
  disabled?: boolean;
  /** Expanded content. */
  children?: React.ReactNode;
  /** Extra CSS class applied to the root element. */
  className?: string;
  /**
   * Show the 1px separator line below this item.
   * @default true
   */
  hasSeparator?: boolean;
}

/** Props for the self-contained BTAccordionCard. */
export interface BTAccordionCardProps {
  /** Card header title text. */
  title: string;
  /** Optional plain subtext below the title. For rich content pass a ReactNode. */
  subtext?: React.ReactNode;
  /** When true, the card is non-interactive and dimmed. */
  disabled?: boolean;
  /** Controlled expanded state. */
  expanded?: boolean;
  /** Called when expanded state changes. */
  onExpandedChange?: (expanded: boolean) => void;
  /** Initial expanded state (uncontrolled). */
  initiallyExpanded?: boolean;
  /** Extra CSS class applied to the root element. */
  className?: string;
  /** Body content. No children = static header (no chevron, not toggleable). */
  children?: React.ReactNode;
}

/* BTAccordionCard styles — Figma 2481:6923
 *
 * Self-contained expandable card with its own header (title + chevron).
 * Body has padding: 0 16px 16px (no top, 16px horizontal + bottom) —
 * nested BTAccordion items provide their own top spacing via 8px header padding.
 * The 16px horizontal aligns item text with the card header title.
 * The 16px bottom gives breathing room before the card edge.
 *
 * Architecture:
 *   .bt-accordion-card               — card root (bg + border + radius-sm)
 *   .bt-accordion-card--open         — expanded state
 *   .bt-accordion-card--disabled     — non-interactive + dimmed
 *   .bt-accordion-card__header       — clickable trigger row (constant padding)
 *   .bt-accordion-card__header--static — non-interactive header (no body slot)
 *   .bt-accordion-card__title-wrap   — flex-col for title + subtext
 *   .bt-accordion-card__title        — 16px/bold primary label
 *   .bt-accordion-card__subtext      — 12px/medium secondary label
 *   .bt-accordion-card__chevron      — rotating arrow icon
 *   .bt-accordion-card__body         — CSS-grid height animating wrapper
 *   .bt-accordion-card__body-inner   — overflow:hidden inner
 *   .bt-accordion-card__body-content — always-on padding (0 16px 16px)
 */

/* ── Card root ───────────────────────────────────────────────────────────── */

.bt-accordion-card {
  background: var(--bg-primary);
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm); /* 6px — Figma radius.sm */
  display: flex;
  flex-direction: column;
  width: 100%;
  box-sizing: border-box;
}

.bt-accordion-card--disabled {
  opacity: 0.5;
  pointer-events: none;
}

/* ── Header button ───────────────────────────────────────────────────────── */

.bt-accordion-card__header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: var(--space-sm);
  width: 100%;
  padding: 12px 16px; /* always 12px top/bottom — does NOT change on expand */
  background: none;
  border: none;
  cursor: pointer;
  user-select: none;
  text-align: start;
}

.bt-accordion-card__header:focus-visible {
  outline: 2px solid var(--color-brand-primary);
  outline-offset: -2px;
}

/* ── Static header — no chevron, no cursor: pointer ─────────────────────── */

.bt-accordion-card__header--static {
  display: flex;
  align-items: flex-start;
  padding: 12px 16px;
  text-align: start;

}

/* ── Title + subtext column ──────────────────────────────────────────────── */

.bt-accordion-card__title-wrap {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
  flex: 1;
  min-width: 0;
}

/* ── Title ───────────────────────────────────────────────────────────────── */

.bt-accordion-card__title {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-md); /* 16px */
  font-weight: var(--typography-font-weight-bold); /* 700 */
  line-height: var(--typography-line-height-sm);
  color: var(--text-primary);
  margin: 0;
}

/* ── Subtext ─────────────────────────────────────────────────────────────── */

.bt-accordion-card__subtext {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-xs); /* 12px */
  font-weight: var(--typography-font-weight-medium); /* 500 */
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  margin: 0;
}

/* ── Chevron ─────────────────────────────────────────────────────────────── */

.bt-accordion-card__chevron {
  flex-shrink: 0;
  width: 16px;
  height: 16px;
  margin-top: var(--space-2xs);
  color: var(--text-secondary);
  display: flex;
  align-items: center;
  justify-content: center;
  transition: transform 0.25s cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-accordion-card--open .bt-accordion-card__chevron {
  transform: rotate(180deg);
}

/* ── Animated body — 3-layer CSS grid height trick ───────────────────────── */
/*
 * Flutter SizeTransition equivalent:
 *   body         → grid 0fr↔1fr + overflow:hidden  (clips body-inner height)
 *   body-inner   → min-height:0 + overflow:hidden  (clips body-content)
 *   body-content → always-on padding               (no class toggle = smooth)
 *
 * Why 3 layers: overflow:hidden never clips an element's OWN padding box.
 * Padding must be on a CHILD so the parent's overflow:hidden can clip it.
 * Without body-content, body-inner's own padding bleeds through when 0fr.
 */

.bt-accordion-card__body {
  display: grid;
  grid-template-rows: 0fr;
  transition: grid-template-rows 0.28s cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-accordion-card--open .bt-accordion-card__body {
  grid-template-rows: 1fr;
}

.bt-accordion-card__body-inner {
  min-height: 0;
  overflow: hidden;
}

.bt-accordion-card__body-content {
  /* 16px horizontal aligns nested BTAccordionItem text with the card header title.
   * 16px bottom gives breathing room before the card edge.
   * No top padding — accordion items provide their own top spacing
   * via their 8px header padding. */
  padding: 0 var(--space-lg) var(--space-lg);
}

/* ── Disabled text colors ────────────────────────────────────────────────── */

.bt-accordion-card--disabled .bt-accordion-card__title {
  color: var(--text-disabled);
}

.bt-accordion-card--disabled .bt-accordion-card__subtext {
  color: var(--text-disabled);
}

/**
 * BTAccordionCard — self-contained expandable card with its own header
 * (Figma 2473:2493).
 *
 * Renders a card (white bg + 1px border + border-radius) with a clickable
 * header row (title + optional subtext + chevron). The body has no default
 * padding — nest a BTAccordion for FAQ-style lists, or wrap content in a div
 * with your own padding.
 *
 * When no children are provided, the header renders as a static non-interactive
 * div (no chevron, no cursor: pointer).
 *
 * @example
 * ```ts
 * // FAQ pattern — card header expands to reveal accordion items
 * // <BTAccordionCard title="Subscription & Billing"
 * //   subtext="Common questions about billing">
 * //   <BTAccordion type="single">
 * //     <BTAccordionItem value="q1" title="How do I cancel?">...</BTAccordionItem>
 * //     <BTAccordionItem value="q2" title="Where is my invoice?">...</BTAccordionItem>
 * //   </BTAccordion>
 * // </BTAccordionCard>
 *
 * // Static header — no children
 * // <BTAccordionCard title="Header - No Content" />
 *
 * // Custom padded content
 * // <BTAccordionCard title="Settings">
 * //   <div style={{ padding: 16 }}>Custom content here</div>
 * // </BTAccordionCard>
 * ```
 */
import './BTAccordionCard.css';
import { useState } from 'react';
import type { BTAccordionCardProps } from './BTAccordion.types';

export function BTAccordionCard({
  title,
  subtext,
  disabled = false,
  expanded,
  onExpandedChange,
  initiallyExpanded = false,
  className,
  children,
}: BTAccordionCardProps) {
  const isControlled = expanded !== undefined;
  const [internalOpen, setInternalOpen] = useState(initiallyExpanded);

  const isOpen = isControlled ? (expanded ?? false) : internalOpen;
  const hasContent = Boolean(children);

  function toggle() {
    if (disabled) return;
    if (!hasContent) return;
    const next = !isOpen;
    if (!isControlled) setInternalOpen(next);
    onExpandedChange?.(next);
  }

  const rootClass = [
    'bt-accordion-card',
    isOpen && 'bt-accordion-card--open',
    disabled && 'bt-accordion-card--disabled',
    className,
  ]
    .filter(Boolean)
    .join(' ');

  return (
    <div className={rootClass}>
      {/* Static header when no children */}
      {!hasContent ? (
        <div className="bt-accordion-card__header--static">
          <span className="bt-accordion-card__title-wrap">
            <span className="bt-accordion-card__title">{title}</span>
            {subtext && <span className="bt-accordion-card__subtext">{subtext}</span>}
          </span>
        </div>
      ) : (
        /* Interactive header when children exist */
        <button
          type="button"
          className="bt-accordion-card__header"
          aria-expanded={isOpen}
          disabled={disabled || undefined}
          onClick={toggle}
        >
          <span className="bt-accordion-card__title-wrap">
            <span className="bt-accordion-card__title">{title}</span>
            {subtext && <span className="bt-accordion-card__subtext">{subtext}</span>}
          </span>

          <span className="bt-accordion-card__chevron" aria-hidden="true">
            <svg
              viewBox="0 0 24 24"
              width="16"
              height="16"
              fill="none"
              xmlns="http://www.w3.org/2000/svg"
            >
              <path
                d="M7.41 8.59 12 13.17l4.59-4.58L18 10l-6 6-6-6 1.41-1.41z"
                fill="currentColor"
              />
            </svg>
          </span>
        </button>
      )}

      {/* Animated body — 3-layer CSS grid height trick */}
      {/* body → body-inner → body-content; see BTAccordionCard.css for why 3 layers */}
      {hasContent && (
        <div className="bt-accordion-card__body" aria-hidden={!isOpen}>
          <div className="bt-accordion-card__body-inner">
            <div className="bt-accordion-card__body-content">{children}</div>
          </div>
        </div>
      )}
    </div>
  );
}

BTAccordionCard.displayName = 'BTAccordionCard';

/**
 * BTAccordionItem — single collapsible panel inside a BTAccordion group.
 *
 * Default visual: separator line at bottom, 14px/medium title. No card chrome.
 * Consumes BTAccordion group context when nested inside one.
 * Falls back to standalone open/close when used without a group.
 * When no children are provided the header renders as a static non-interactive
 * div (no chevron, no cursor: pointer).
 *
 * @example
 * ```ts
 * // <BTAccordionItem value="item-1" title="My title"
 * //   subtext={<span style={{ color: 'var(--color-brand-primary)' }}>Custom</span>}>
 * //   <p>Content goes here</p>
 * // </BTAccordionItem>
 * ```
 */
import { useState } from 'react';
import { useAccordionContext } from './BTAccordion';
import type { BTAccordionItemProps } from './BTAccordion.types';

export function BTAccordionItem({
  value,
  title,
  subtext,
  disabled,
  className,
  children,
  hasSeparator = true,
}: BTAccordionItemProps) {
  const group = useAccordionContext();
  const [standaloneOpen, setStandaloneOpen] = useState(false);

  const isOpen = group ? group.isItemOpen(value) : standaloneOpen;
  const hasContent = Boolean(children);

  function toggle() {
    if (disabled) return;
    if (group) {
      group.toggle(value);
    } else {
      setStandaloneOpen((prev) => !prev);
    }
  }

  const rootClass = [
    'bt-accordion',
    isOpen && 'bt-accordion--open',
    disabled && 'bt-accordion--disabled',
    className,
  ]
    .filter(Boolean)
    .join(' ');

  return (
    <div className={rootClass}>
      {/* Static header when no children */}
      {!hasContent ? (
        <div className="bt-accordion__header--static">
          <span className="bt-accordion__title-wrap">
            <span className="bt-accordion__title">{title}</span>
            {subtext && <span className="bt-accordion__subtext">{subtext}</span>}
          </span>
        </div>
      ) : (
        /* Interactive header when children exist */
        <button
          type="button"
          className="bt-accordion__header"
          aria-expanded={isOpen}
          disabled={disabled}
          onClick={toggle}
        >
          <span className="bt-accordion__title-wrap">
            <span className="bt-accordion__title">{title}</span>
            {subtext && <span className="bt-accordion__subtext">{subtext}</span>}
          </span>

          <span className="bt-accordion__chevron" aria-hidden="true">
            <svg
              viewBox="0 0 24 24"
              width="16"
              height="16"
              fill="none"
              xmlns="http://www.w3.org/2000/svg"
            >
              <path
                d="M7.41 8.59 12 13.17l4.59-4.58L18 10l-6 6-6-6 1.41-1.41z"
                fill="currentColor"
              />
            </svg>
          </span>
        </button>
      )}

      {/* Animated content body — CSS grid height trick */}
      {hasContent && (
        <div className="bt-accordion__body" aria-hidden={!isOpen}>
          <div className="bt-accordion__body-inner">
            <div className="bt-accordion__body-content">{children}</div>
          </div>
        </div>
      )}

      {/* Separator (always shown when hasSeparator is true) */}
      {hasSeparator && <div className="bt-accordion__separator" aria-hidden="true" />}
    </div>
  );
}

BTAccordionItem.displayName = 'BTAccordionItem';
